def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 6):
            factor = j * utilization
            if factor < 0.3:
                score += np.exp(-factor) * np.sin(factor * np.pi)
            elif 0.3 <= factor < 0.7:
                val = factor + 1
                if val != 0:
                    score += np.log(val) * np.cos(factor * np.pi)
                else:
                    score += 0
            elif 0.7 <= factor < 1:
                score += factor ** 3 - np.sqrt(factor)
            else:
                score += factor ** 2 + np.log1p(factor)
        if bin_capacity < item * 1.5:
            score *= 2
        elif item * 1.5 <= bin_capacity <= item * 3:
            for k in range(1, 4):
                mod_factor = score / (k + 1)
                score += np.tanh(mod_factor) * k
        elif bin_capacity > item * 5:
            score *= 0.5
            extra_penalty = 0
            for m in range(1, 7):
                penalty_factor = np.sin(m * utilization * np.pi)
                if penalty_factor > 0:
                    extra_penalty += penalty_factor ** 2
                else:
                    extra_penalty -= penalty_factor
            score += extra_penalty * 0.1
        if int(bin_capacity) % 2 == 0:
            score /= 1.1
        else:
            score *= 1.1
        priorities[i] = score if score >= 0 else float('inf')
    return priorities
